10	type Item = { type: string };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
15	
16	const quotePremium = (items: Item[]): number => {
17	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
18	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
19	  return Math.ceil(basePremium + firstInsurance) + PROCESSING_FEE;
20	};
21	
22	export const runScenario = (scenario: Scenario): unknown => {
23	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
24	  return { results };
25	};
